export function AirdropBanner() {
  return (
    <svg
      width="388"
      height="188"
      viewBox="0 0 388 188"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
    >
      <g clipPath="url(#clip0_1_1017)">
        <rect
          width="387.38"
          height="187.17"
          rx="6"
          fill="url(#pattern0_1_1017)"
        />
      </g>
      <defs>
        <pattern
          id="pattern0_1_1017"
          patternContentUnits="objectBoundingBox"
          width="1"
          height="1"
        >
          <use
            xlinkHref="#image0_1_1017"
            transform="scale(0.0015625 0.00323625)"
          />
        </pattern>
        <clipPath id="clip0_1_1017">
          <rect width="387.39" height="187.17" fill="white" />
        </clipPath>
        <image
          id="image0_1_1017"
          width="640"
          height="309"
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
}

